INSERT INTO products VALUES(2,2,1,'Teléfono Xiaomi 15t Pro 12 GB RAM 1 TB ROM Triple Camera','telefono-xiaomi-15t-pro-12-gb-ram-1-tb-rom-triple-camera-69bc67a13b74d',unistr('Descripción\u000aXiaomi 15T Pro\u000a\u000aNota:\u000a*This phone is a global version.\u000a\u000aBandas de red:\u000aGSM: 2/3/5/8\u000aWCDMA: B1/2/4/5/6/8/19\u000aLTE FDD: B1/2/3/4/5/7/8/12/13/17/18/19/20/25/28/32/66/71\u000aLTE TDD: B38/39/40/41/42/48\u000a5G SA: n1/2/3/5/7/8/12/25/26/28/38/40/41/48/66/71/75/77//78\u000a5G NSA: n1/3/5/7/8/20/28/38/40/41/66/71/75/77/78\u000a\u000a****************************************************************************************\u000a\u000aEspecificaciones:\u000a\u000aProcesador:\u000aMediaTek Dimensity 9400+\u000a\u000aRAM and storage:\u000a12 GB + 1 TB\u000aRAM: LPDDR5X, Storage: UFS 4.1\u000a\u000aDimensions:\u000a162,7 mm x 77,9 mm x 7,96 mm\u000aPeso: 210 g\u000a\u000aPantalla:\u000aPantalla de 6,83 con 144 Hz eye care\u000aPantalla plana, AMOLED\u000aCristal Corning Gorilla Glass 7i\u000aResolution: 2772 x 1280, 447 ppp\u000aRefresco Frequency: until 144 Hz\u000a\u000aCamera:\u000aCame back:\u000aOptical Lent Leica Summilux\u000aVARIO-SUMMILUX 1:1,62-3 ,0/15-115 ASPH..\u000aCámara principal Leica de 23 mm: 50 MP\u000aCámara con superteleobjetivo Leica de 115 mm: 50 MP\u000aCámara Leica ultra gran angular de 15 mm: 12 MP\u000aCámara frontal:\u000aCámara selfie en pantalla de 32 MP\u000a\u000aBattery and charge:\u000aXiaomi Surge de 5500 mAh (typ)\u000aHyperCharge de 90 W\u000aHyperCharge inalámbrica de 50 W\u000aAdmite PD 3.0 y PD 2.0\u000aPuerto de carga USB-C\u000a\u000aXiaomi HyperAI:\u000aEscritura con IA, Reconocimiento de voz con IA, Intérprete con IA, Búsqueda con IA, Fondos dinámicos de IA, Asistente de creatividad con AI/Y mucho más.\u000aRodea para buscar con Google\u000aGoogle Gemini\u000a\u000aSeguridad y autenticación:\u000aSensor de huellas dactilares en pantalla\u000aDesbloqueo facial con AI\u000a\u000aConectividad:\u000aSIM dual (nano SIM + nano SIM o nano SIM + eSIM o eSIM + eSIM) *\u000aCapacidad Wi-Fi 7/Bluetooth 6.0/ NFC\u000a\u000aSistema de refrigeración:\u000aSistema Xiaomi 3D IceLoop\u000a\u000aResistencia al polvo y al agua:\u000aIP68*\u000a\u000aSensor:\u000aSensor de proximidad/ Sensor de luz ambiental/Acelerómetro/Giroscopio/Brújula electrónica/Emisor de infrarrojos/Sensor de parpadeo /Motor de vibración lineal de eje X/ Sensor de temperatura de color\u000a\u000aSistema operativo:\u000aXiaomi HyperOS 2\u000a\u000a****************************************************************************************************************************************************************************************************************************************************************************************************************************************************************************************************************\u000a\u000aTeleobjetivo Leica 5x Pro\u000aVive la historia de cerca\u000aEl primer teleobjetivo 5x de la serie Xiaomi T, con zoom óptico de 5x, zoom de nivel óptico de 10x y Ultra zoom de 20x o más, combinado con la óptica Leica para acercarte a esas historias que parecían tan lejanas.\u000a\u000aTriple cámara Leica\u000aLa versatilidad de una cámara profesional\u000aLa emblemática configuración de triple cámara captura imágenes amplias, lejanas y nítidas para lograr resultados de nivel superior con fotos impresionantes sin esfuerzo.\u000a115 mm Teleobjetivo profesional Leica 5x Pro\u000a23 mm Cámara principal Leica de nivel profesional\u000a15 mm Ultra gran angular Leica\u000aCámara principal\u000aLente óptica Leica Summilux\u000aCalidad de imagen cristalina para fotos cautivadoras\u000aLa lente óptica Leica Summilux, con su abertura ultragrande y su excepcional performance óptico, reproduce con precisión los colores y ofrece detalles claros y cautivadores incluso con poca luz.\u000aLight Fusion 900\u000aSensor de alto rango dinámico\u000aCon un sensor clásico de gama alta y un rango dinámico de 13,5 EV, comparable al de las cámaras profesionales, captura con precisión momentos de luz y sombra realmente espectaculares.\u000aSistema de triple cámara, cinco distancias focales\u000aCaptura como un profesional\u000aCon un rango focal de 15 a 230 mm y un zoom fluido, podrás acercarte o alejarte con total naturalidad.\u000a\u000aDiseño insignia\u000aMinimalista y elegante, con una imagen de alta gama\u000aLa sencillez es arte. La cubierta trasera se integra a la perfección con el cuerpo, y las líneas limpias y los contornos suaves se entrelazan en un conjunto en el que cada detalle es pura belleza.\u000aDiseño curvo y estilizado\u000aTacto suave y sujeción cómoda\u000aLos contornos suavemente redondeados y el acabado mate crean un diseño refinado, equilibrado y elegante.\u000a\u000aExcepcional por dentro y por fuera\u000aDurabilidad a toda prueba\u000aIP68 Resistencia al agua y al polvo\u000aResistencia mejorada al agua, hasta 3 m de profundidad.\u000aMejor resistencia a los arañazos: Incluye cristal Corning Gorilla Glass 7i para una mayor tranquilidad\u000aMejor\u000aResistencia a las caídas: Diseñado con un marco de aleación de aluminio de alta resistencia y una cubierta trasera de fibra de vidrio para una mayor resistencia a las caídas.\u000a\u000aCon una pantalla de gran tamaño de 6,83 pulgadas recién actualizada con un diseño de bisel ultraestrecho y una alta resolución de 1,5K, ofrece un campo de visión más amplio y un nivel de detalle impresionante.\u000aLa frecuencia de muestreo táctil instantáneo de 2560 Hz debe activarse en el modo Game Turbo.\u000aUltrabrillante de 3200 nits\u000a\u000aPantalla con cuidado visual y tecnología sin parpadeos\u000aNaturalidad y comodidad\u000aLas capacidades mejoradas de protección visual proporcionan una atención multidimensional de la salud ocular.\u000a\u000aAI display\u000aFácil de ver y de usar\u000a\u000aConectividad rápida y estable\u000aXiaomi Astral Communication\u000aXiaomi Surge T1S Tuner\u000aCon el Xiaomi Surge T1S Tuner, de desarrollo propio, el Xiaomi 15T Pro optimiza las señales Wi-Fi, Bluetooth, GPS y móviles para ofrecer una conectividad más fluido e inteligente.\u000aSuperconjunto de antena\u000aGracias a una matriz de antenas de alto rendimiento, optimiza el rendimiento en 16 escenarios para mantener la conexión en cualquier momento y lugar.\u000a\u000aDimensity 9400+\u000aCaracterístico proceso de 3 nm\u000aMediaTek Dimensity 9400+ ofrece una respuesta ultrafluida incluso en aplicaciones exigentes y juegos con gran carga gráfica. Con una eficiencia térmica excepcional y una estabilidad constante, garantiza un rendimiento máximo sin concesiones.\u000a\u000a5500 mAh (típico)\u000aRendimiento líder en duración de la batería\u000aCon la batería más grande de la serie Xiaomi T, ofrece una gran duración en un diseño estilizado. Equipado con el sistema de gestión de la batería Xiaomi Surge y 64 capas de protección de seguridad para ofrecerte la máxima durabilidad y tranquilidad.\u000aSistema Xiaomi 3D IceLoop\u000aFrescura y eficiencia\u000aEl sistema de refrigeración 3D se adhiere estrechamente al chip para una rápida disipación del calor, lo que permite una refrigeración eficiente y un rendimiento sostenido.\u000aHyperCharge de 90 W\u000aTecnología HyperCharge inalámbrica de 50 W\u000aEquipado con el nuevo chip Xiaomi Surge P3 para mejorar aún más el rendimiento.\u000a\u000a********************************************************************************************\u000a\u000a1. Algunas de las funciones del asistente de creatividad con IA requieren conexión a Internet y pueden variar según el software del sistema y las versiones de la aplicación Editor de Galería. Consulta la experiencia de uso real.\u000a2. Película de IA disponible en algunos idiomas. Es necesaria una conexión a Internet. Comprueba la precisión de las respuestas.\u000a3. Grabación en 4K a 120 fps disponible solo con la cámara principal.\u000a4. El dispositivo se ha probado y certificado en condiciones específicas de laboratorio para cumplir el estándar de protección IP68 (IEC 60529:1989 +A 1:1999 +A 2:2013), lo que garantiza la resistencia a las salpicaduras, al agua y al polvo. Durante la prueba, el dispositivo se sumergió en agua dulce estática a una profundidad de 3 metros durante 30 minutos, con una diferencia de temperatura máxima de 5 °C entre el agua y el dispositivo. Las condiciones de la prueba de laboratorio no reflejan el uso diario. La resistencia al agua puede verse comprometida si el dispositivo se expone a entornos fuera de estas condiciones de prueba, como agua salada, agua con cloro o agua a alta presión. No recomendamos probar la resistencia al agua ni usar el dispositivo en la playa o en piscinas. La protección frente a la entrada de agua puede deteriorarse con el tiempo debido al uso normal, a daños físicos o a reparaciones que requieran el desmontaje. No carga el dispositivo, ni presiona los botones físicos o extrae la bandeja SIM cuando esté mojado o expuesto a la humedad. Para obtener instrucciones de seguridad detalladas, consulte el manual de usuario. Los daños causados por líquidos fuera de las condiciones de la prueba IP68 no están cubiertos por la garantía.\u000a5. Los datos relacionados con la rigidez han sido probados por los laboratorios internos de Xiaomi; los resultados reales pueden variar.\u000a6. El resto de productos de la colección Gold deben adquirirse por separado.\u000a7. La pantalla admite una frecuencia máxima de actualización de 144 Hz. La frecuencia de actualización puede variar según la interfaz de la aplicación y la calidad de imagen del juego. Consulta la experiencia real.\u000a8. La frecuencia de muestreo táctil instantáneo de 2560 Hz debe activarse en el modo Game Turbo.\u000a9. Los datos relacionados con los biseles han sido probados por los laboratorios internos de Xiaomi; los resultados reales pueden variar.\u000a10. Los datos relacionados con la relación de pantalla a cuerpo del 94,5% han sido probados por los laboratorios internos de Xiaomi; los resultados reales pueden variar.\u000a11. Adaptador de corriente no incluido. Se recomienda usar un adaptador de corriente de Xiaomi de 67 W o más.\u000a12. Los cargadores inalámbricos se venden por separado. La disponibilidad puede variar según el país o la región.'),0,0,'KMA-HCDNZE4D','["data:image\/jpeg;base64,\/9j\/4AAQSkZJRgABAQAAAQABAAD\/2wCEAAUDBAgFCAgFBQgGBQUFBgUFBQUFBQUFBQUFBQgIBgUFBQUHChALBwgOCQgHDRUNDhERExMTCAsWGBYSGBASExIBBQUFCAcICAgIBxIIBwgSEhISEhISEhISEhISEhISEhISEhISEhISEhISEhISEhIeEhISEhISEhISEhISEh4SEv\/AABEIAtAFAAMBIgACEQEDEQH\/xAAdAAEAAgMBAQEBAAAAAAAAAAAAAQIDBAUGBwgJ\/8QAaxAAAgECAwMGCAkGBwkMBgkFAAIBAwQFERIGISITMTJBQlIHFFFhYnKC8AhxgZGSoaKx0RUjssHC0hYkM0Ph4vIJJjRTc3WztPEXJTZEVFVjdIOTldQ1VmSFw9NGZnaElJaltcUYJzdlhv\/EABkBAQEBAQEBAAAAAAAAAAAAAAABAgMEBf\/EAC4RAQEAAgEDAwMEAQQDAQAAAAABAhEhAxIxE0FRBFJxIjJhgUJykbHwodHxYv\/aAAwDAQACEQMRAD8A\\\/WaptV+jPv1wap7smAAiSBJEjMgCZIAAiSSJIAAAAAJCokgAICRmAIAAAiSSsmQkSCAAABAESSFCpYqAAKhAAZgMyJJIAAAihWQAABAAAAAAECsiQFRJAEgACAAAAAACJIAMgAABAAaRkSRmSAALKoEA9BgOyN9icx4rQqaG7broT55PcYR4Gbirk13XSl3kpLr+0NMvk+kiYPvVr4FrZf5WpcVW9HSpur4HbBexXb1nLo2\/O8wVyP0cvggw\/8AxNRm\/wArJdPBJh+f+Dy3xuw7Tb82kSfpePBRh3R8W+2xZfBZYZ\/4JT9rUO1dvzMD9O\/7mNgscNpSb1lklPBpZr\/xS3+hmO1Nvy\/Mg\/UU+DuzXo2luv8A2Slv9z+2X\/ituv8A2SDsO5+Wxl5pP1KuwdDs29v\/AN0n4GSNiKKxw0KHF\/0KfgPTNvyrpnyT80kwk92fosfqeNiqcfzVBdP\/AESfgXnY1OlydP5KSfgOw7n5Xik\/cf6E\/gPF6jfzdT\/un\/A\/VU7Jr3E+gpVtk18iL7Kj0\/8A9Hc\/LEWlVv5qr\/3T\/gW8Rr\/4mv8A90\/4H6l\/govvpXV6KmN9llafpMq9H2R6Z3PzB+TLiejQr\/8Acv8AgTGE3TdG3uP+6f8AA\/TsbLqs55+\/dK\/wWTOWz09L1uIemnc\/M0YNd\/8AJ6\/\/AHUllwO8aNXi1fL1D9Krsuq5Nn7Mr+0VfZmnOSZz3ej0R6Z3PzZGBXjZr4vV4eluX8SfyBef8nqe1pX75P0l\/BallzwrRxN0eL2esxts3RadLRGTdqel7JfSh3Pzn\/B29\/xD8XpJ+Jb+Dd7\/AIn7afifoapsxRznTPR0svq934yr7O0dyx0efh08O7ok9KHc\/Pc7OXa\/zcf96vvmW\/gzd92n\/wB6vvmff32eocLbpXPhbUqrwxz\/ABGOns7brMNuZZ7v9PWX0odz4HOzd0vPFNfWq\/0Cdm7jPSvJN6rt+B95qYFQbPVkuni6Or7UmKcCoLOen7Kt0eyvm5h6UO58KbZy4WdLTTVvJqfi9Xc