PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "avatar" varchar, "phone" varchar, "is_seller" tinyint(1) not null default '0', "is_admin" tinyint(1) not null default '0', "remember_token" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "categories" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "image" varchar, "parent_id" integer, "is_active" tinyint(1) not null default '1', "sort_order" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("parent_id") references "categories"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "products" ("id" integer primary key autoincrement not null, "user_id" integer not null, "category_id" integer, "name" varchar not null, "slug" varchar not null, "description" text, "price" numeric not null, "stock" integer not null default '0', "sku" varchar not null, "images" text, "is_active" tinyint(1) not null default '1', "type" varchar check ("type" in ('direct', 'auction', 'both')) not null default 'direct', "specifications" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("category_id") references "categories"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "auctions" ("id" integer primary key autoincrement not null, "product_id" integer not null, "starting_price" numeric not null, "current_price" numeric not null, "reserve_price" numeric, "buy_now_price" numeric, "starts_at" datetime not null, "ends_at" datetime not null, "is_active" tinyint(1) not null default '1', "has_reserve" tinyint(1) not null default '0', "winner_id" integer, "status" varchar check ("status" in ('pending', 'active', 'ended', 'cancelled')) not null default 'pending', "created_at" datetime, "updated_at" datetime, foreign key("product_id") references "products"("id") on delete cascade, foreign key("winner_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "bids" ("id" integer primary key autoincrement not null, "auction_id" integer not null, "user_id" integer not null, "amount" numeric not null, "is_winning" tinyint(1) not null default '0', "ip_address" varchar, "created_at" datetime not null default CURRENT_TIMESTAMP, "updated_at" datetime not null default CURRENT_TIMESTAMP, foreign key("auction_id") references "auctions"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "orders" ("id" integer primary key autoincrement not null, "user_id" integer not null, "order_number" varchar not null, "status" varchar check ("status" in ('pending', 'processing', 'shipped', 'delivered', 'cancelled')) not null default 'pending', "subtotal" numeric not null, "shipping_cost" numeric not null default '0', "total" numeric not null, "payment_status" varchar check ("payment_status" in ('pending', 'paid', 'failed', 'refunded')) not null default 'pending', "payment_method" varchar, "payment_id" varchar, "notes" text, "shipping_address_id" integer, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("shipping_address_id") references "addresses"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "order_items" ("id" integer primary key autoincrement not null, "order_id" integer not null, "product_id" integer not null, "seller_id" integer not null, "quantity" integer not null, "price" numeric not null, "total" numeric not null, "type" varchar not null default 'direct', "auction_id" integer, "created_at" datetime, "updated_at" datetime, foreign key("order_id") references "orders"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade, foreign key("seller_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "addresses" ("id" integer primary key autoincrement not null, "user_id" integer not null, "label" varchar not null default 'Principal', "recipient_name" varchar not null, "phone" varchar not null, "address" varchar not null, "number" varchar not null, "floor" varchar, "apartment" varchar, "city" varchar not null, "state" varchar not null, "postal_code" varchar not null, "observations" text, "is_default" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "cart_items" ("id" integer primary key autoincrement not null, "user_id" integer not null, "product_id" integer not null, "quantity" integer not null default '1', "price" numeric not null, "type" varchar check ("type" in ('direct', 'auction')) not null default 'direct', "auction_id" integer, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "notifications" ("id" integer primary key autoincrement not null, "user_id" integer not null, "type" varchar not null, "title" varchar not null, "message" text not null, "data" text, "is_read" tinyint(1) not null default '0', "read_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "categories_slug_unique" on "categories" ("slug");
CREATE UNIQUE INDEX "products_slug_unique" on "products" ("slug");
CREATE UNIQUE INDEX "products_sku_unique" on "products" ("sku");
CREATE UNIQUE INDEX "orders_order_number_unique" on "orders" ("order_number");
CREATE UNIQUE INDEX "cart_items_user_id_product_id_type_unique" on "cart_items" ("user_id", "product_id", "type");
COMMIT;
